import { TooltipRoot, type TooltipProps } from "./tooltip";
import {
  PopoverTrigger as TooltipTrigger,
  type PopoverTriggerProps as TooltipTriggerProps,
  type PopoverTriggerRenderProps as TooltipTriggerRenderProps,
} from "../popover/popover-trigger";
import {
  TooltipContent,
  type TooltipContentProps,
} from "./tooltip-content";

const Tooltip = Object.assign(TooltipRoot, {
  Trigger: TooltipTrigger,
  Content: TooltipContent,
});

export { Tooltip, type TooltipProps };
export {
  TooltipTrigger,
  TooltipContent,
  type TooltipTriggerProps,
  type TooltipTriggerRenderProps,
  type TooltipContentProps,
};

"use client";

import type { ReactNode } from "react";
import { PopoverRoot } from "../popover/popover";
import { PopoverTrigger } from "../popover/popover-trigger";
import { TooltipContent } from "./tooltip-content";

export interface TooltipProps {
  children: ReactNode;
  content?: ReactNode;
  enabled?: boolean;
  delayMs?: number;
  closeDelayMs?: number;
  open?: boolean;
  defaultOpen?: boolean;
  onOpenChange?: (open: boolean) => void;
}

export function TooltipRoot({
  children,
  content,
  enabled = true,
  delayMs = 500,
  closeDelayMs,
  open,
  defaultOpen,
  onOpenChange,
}: TooltipProps) {
  return (
    <PopoverRoot
      triggerMode="hover"
      enabled={enabled}
      delayMs={delayMs}
      closeDelayMs={closeDelayMs}
      open={open}
      defaultOpen={defaultOpen}
      onOpenChange={onOpenChange}
    >
      {content != null ? (
        <>
          <PopoverTrigger>{children}</PopoverTrigger>
          <TooltipContent>{content}</TooltipContent>
        </>
      ) : (
        children
      )}
    </PopoverRoot>
  );
}

"use client";

import { cn } from "@/lib/utils";
import { PopoverContent, type PopoverContentProps } from "../popover/popover-content";

export interface TooltipContentProps extends Omit<PopoverContentProps, "autoFocus"> {}

export function TooltipContent({
  children,
  side = "top",
  align = "center",
  sideOffset = 4,
  className,
  ...rest
}: TooltipContentProps) {
  return (
    <PopoverContent
      side={side}
      align={align}
      sideOffset={sideOffset}
      className={cn(
        "max-w-xs border border-border bg-background px-2 py-1 font-mono text-xs text-foreground shadow-md",
        className,
      )}
      {...rest}
    >
      {children}
    </PopoverContent>
  );
}
